-- ── AppNexus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AppNexus was a programmatic advertising exchange founded in 2007, acquired by AT&amp;T in 2018 and rebranded as Xandr; its assets are now part of Microsoft Advertising after Microsoft acquired Xandr in 2022.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York City, New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$AppNexus in 2026: What Happened to It and Where It Is Now$q$, seo_title),
  seo_meta_description = COALESCE($q$AppNexus was acquired by AT&amp;T in 2018, rebranded Xandr, then sold to Microsoft in 2022. See its history and current status inside Microsoft Advertising.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$AppNexus was an independent programmatic advertising exchange founded in September 2007 by Brian O'Kelley and Mike Nolet, headquartered in New York City. It became one of the largest ad exchanges and demand/supply-side platforms in the advertising technology industry, raising roughly 250 million US dollars from investors including Microsoft, Khosla Ventures, First Round Capital, Venrock, Marc Andreessen, and Ben Horowitz. In June 2018, AT&amp;T acquired AppNexus for a reported 1.6 billion US dollars to build out its advertising business, and in September 2018 AT&amp;T folded AppNexus into a newly formed unit called Xandr, which also absorbed AT&amp;T's other ad tech assets. Xandr rebranded the AppNexus demand-side platform as Xandr Invest and continued operating the exchange and supply-side tools under the Xandr name. In December 2021, AT&amp;T agreed to sell Xandr, including the former AppNexus technology, to Microsoft; the deal closed in June 2022. Microsoft initially operated the business as Xandr before retiring the Xandr brand in 2023 and folding its functions into Microsoft Advertising. As of 2026, the AppNexus lineage has effectively ended as a standalone brand: Microsoft announced it would shut down Microsoft Invest, the demand-side platform descended from the original AppNexus DSP, effective February 28, 2026, shifting its ad-buying strategy toward a Copilot-powered, conversational and agentic advertising product. The supply-side and publisher-facing ad tech that also traces back to AppNexus continues to operate under the Microsoft Monetize brand. For a software directory, AppNexus should therefore be presented as a historically important, now-defunct independent brand rather than an active current product; anyone searching for 'AppNexus' today is generally looking for either its acquisition history or its modern successor technology inside Microsoft's advertising stack, not a live, independently purchasable product with its own pricing or sign-up flow.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '153bb0d9-7c3e-4e52-ad03-b3d915a1ecdf';

