-- ── Aptana ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Aptana Studio was a free, open-source Eclipse-based IDE for web development, later owned by Appcelerator and then Axway; it has not received a stable release since 2018 and is effectively unmaintained today.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Mateo, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Aptana Studio in 2026: Is It Still Maintained or Discontinued$q$, seo_title),
  seo_meta_description = COALESCE($q$Aptana Studio is a free, open-source web IDE now under Axway. See its history, features, and current unmaintained status heading into 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Aptana was a software company founded in 2005 by Paul Colton in San Mateo, California, best known for Aptana Studio, a free and open-source integrated development environment (IDE) built on the Eclipse platform for web application development, supporting HTML, CSS, JavaScript, PHP, Ruby, and Python among other languages. Aptana raised approximately 20.3 million US dollars in funding from investors including Accel and Rembrandt Partners, and Aptana Studio was downloaded more than 4 million times during its active years. In January 2011, Aptana was acquired by Appcelerator, a mobile app development platform company, which continued to develop and distribute Aptana Studio alongside its own Titanium mobile SDK products. In January 2016, Appcelerator itself was acquired by Axway, an enterprise API management and secure data exchange company, which has continued to list Aptana on its website (axway.com/en/aptana) primarily as a legacy download and reference page rather than an actively developed product line. As of the current date, Aptana Studio's last stable release remains version 3.7.2, published in July 2018, with no official updates, security patches, or new feature releases since that date. The public GitHub repository for Aptana Studio 3 remains available under the GNU General Public License version 3, allowing downloads, forks, and community contributions, but shows minimal official activity from Axway, with the most recent commits dating to around 2020 and no published roadmap for future development. In practice, Aptana Studio should be considered inactive/unmaintained rather than formally discontinued: the software still exists, can still be downloaded and run, and remains open source, but it receives no meaningful vendor support, security updates, or compatibility fixes for modern web development workflows. Developers evaluating Aptana Studio today are better served by actively maintained, modern alternatives such as Visual Studio Code, WebStorm, or Sublime Text, all of which offer current language support, extension ecosystems, and active security patching that Aptana Studio can no longer provide. There is no commercial pricing associated with Aptana Studio; it was and remains a free, open-source tool.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '15dd2a6d-755d-4631-9b8f-1094cc7d1a9c';

