-- ── Apttus ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Apttus was a contract lifecycle management (CLM) and configure-price-quote (CPQ) software company founded in 2006; it merged with Conga in 2020 and adopted the Conga name, so apttus.com now redirects to conga.com.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Mateo, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Apttus in 2026: Why It Is Now Called Conga$q$, seo_title),
  seo_meta_description = COALESCE($q$Apttus was a CLM and CPQ software company that merged with Conga in 2020 and took the Conga name. See its history and where the brand stands today.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Apttus was a contract lifecycle management (CLM) and configure-price-quote (CPQ) software company founded in 2006 by Kirk Krappe, Neehar Giri, and Kent Perkocha, headquartered in San Mateo, California. The company was bootstrapped in its early years, taking no outside investment until 2013, when it raised a 37 million US dollar Series A round from investors including K1 Capital, ICONIQ, and Salesforce, reflecting its deep integration with the Salesforce ecosystem, on which many of its products were built as native applications. Apttus grew into one of the leading providers of quote-to-cash software, covering CPQ, CLM, revenue management, and related deal-desk and commercial operations tools, competing with vendors like Salesforce CPQ (formerly SteelBrick), Icertis, and DocuSign CLM. On May 7, 2020, Apttus announced it would acquire fellow quote-to-cash and document automation company Conga in a deal valued at approximately 715 million US dollars; notably, the combined company chose to adopt the Conga brand name going forward rather than keeping the Apttus name, with former Apttus CEO Frank Holland leading the newly combined Conga as CEO. The merged company reported roughly 400 million US dollars in combined GAAP revenue and more than 10,000 enterprise and mid-market customers at the time of the deal, spanning CPQ, CLM, document generation, process automation, and eSignature. As a result, Apttus no longer exists as an active, independently branded product or company; the apttus.com domain redirects (HTTP 301) directly to conga.com, and all of Apttus's former CPQ and CLM product lines are now marketed, sold, and supported under the Conga brand. For a software directory, Apttus should be presented clearly as a legacy brand name that customers and researchers may still search for, with the accurate current-state guidance being to evaluate Conga directly for CPQ, CLM, and quote-to-cash software, rather than presenting Apttus as a currently active, separately purchasable product with its own live pricing or sign-up process.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f324abc7-5879-48b9-8424-5b257644334b';

